// Код для форматирования даты и времени в российском формате для n8n
// Входная дата: 2025-08-04T15:56:12.178+03:00

const date = new Date($input.first().json.currentDate);

// Форматирование даты (ДД.ММ.ГГГГ)
const day = String(date.getDate()).padStart(2, '0');
const month = String(date.getMonth() + 1).padStart(2, '0');
const year = date.getFullYear();

// Форматирование времени (ЧЧ:ММ:СС)
const hours = String(date.getHours()).padStart(2, '0');
const minutes = String(date.getMinutes()).padStart(2, '0');
const seconds = String(date.getSeconds()).padStart(2, '0');

// Возвращаем различные форматы
return [{
  formattedDate: `${day}.${month}.${year}`,
  formattedTime: `${hours}:${minutes}:${seconds}`,
  formattedDateTime: `${day}.${month}.${year} ${hours}:${minutes}:${seconds}`,
  formattedDateTimeShort: `${day}.${month}.${year} ${hours}:${minutes}`
}];

// Альтернативный вариант с использованием toLocaleString для российской локали:
/*
const date = new Date($input.first().json.currentDate);

return [{
  formattedDate: date.toLocaleDateString('ru-RU'),
  formattedTime: date.toLocaleTimeString('ru-RU'),
  formattedDateTime: date.toLocaleString('ru-RU'),
  formattedDateTimeCustom: date.toLocaleString('ru-RU', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  })
}];
*/

// Получаем текст из нового формата данных
const fullText = $input.first().json.result;$input.first().json.result

// Логируем для отладки
console.log('Input text length:', fullText.length);
console.log('First 100 chars:', fullText.substring(0, 100));

// Разделяем по разделителю " --- " (с пробелами)
const tasks = fullText.split(' --- ');

// Создаем отдельные элементы для каждого ТЗ
const result = tasks.map((task, index) => {
  return {
    task_number: index + 1,
    task_content: task.trim(),
    total_tasks: tasks.length,
    content_length: task.trim().length,
  };
});

console.log('Total tasks found:', result.length);

return result;

// Получаем текст напрямую из Gemini API
const input = $('When Executed by Another Workflow').first().json.Tasks;

// Логируем входные данные для отладки
console.log('Input text:', input);
console.log('Input type:', typeof input);

// Проверяем, что input - это строка
let result = '';
if (typeof input === 'string') {
  result = input;
} else {
  console.log('Error: Input is not a string, received:', input);
  return [{ json: { error: 'Invalid input type', received: input } }];
}

// Удаляем все \r, \n, \t, заменяя на пробел
let cleanedText = result.replace(/[\r\n\t]+/g, ' ');

// Заменяем маркеры "•" и "●" на дефис
cleanedText = cleanedText.replace(/[•●]/g, '-');

// Убираем лишние пробелы (больше одного подряд)
cleanedText = cleanedText.replace(/ +/g, ' ').trim();

return [
  {
    json: {
      result: cleanedText,
      original_length: result.length,
      cleaned_length: cleanedText.length
    }
  }
];

